                setglobal("ADKP_Personal_FrameIncludeSubCaptain", this)
                if WebDKP_Options and WebDKP_Options["IncludeSubCaptain"] then
                  this:SetChecked(true)
                end


                if not WebDKP_Options then
                  WebDKP_Options = {}
                end
                WebDKP_Options["IncludeSubCaptain"] = this:GetChecked() and true or false




























	                setglobal("ADKP_Personal_FrameQuickFloatEnabled", this)
	                if not WebDKP_Options then
	                  WebDKP_Options = {}
	                end
	                if WebDKP_Options["QuickFloatEnabled"] then
	                  this:SetChecked(true)
	                end


	                if not WebDKP_Options then
