	                setglobal("ADKP_Personal_FrameSilentMode", this)
	                if not WebDKP_Options then
	                  WebDKP_Options = {}
	                end
	                if WebDKP_Options["SilentMode"] then
	                  this:SetChecked(true)
	                end


	                if not WebDKP_Options then
